        this.isLoading = false;
        console.log('שגיאה כללית', err.message);
        console.log('קוד סטטוס', err.status);

        // כאן ניגשים ל-details
        if (err.error && err.error.details) {
          alert('פרטי השגיאה:' + err.error.details);
          return;
        }
      }
    });
  }
