  addToCart(giftId: number) {
    if (!this.cartUserId) {
      this.addToGuestCart(giftId);
      return;
    }

    this.cartService.AddGiftToCart({ userId: this.cartUserId, giftId }).subscribe({
      next: (data) => {
        console.log(`Gift ${giftId} added to cart`, data);
        // אפשר להוסיף הודעה יפה ל-Popup / Toast
      },
      error: (err) => {
        console.error('Error adding gift to cart', err);
        alert('לא ניתן להוסיף את המתנה לסל (ייתכן שכבר נרכשה)');
      }
    });
  }
  addToGuestCart(giftId: number) {
    const cart = JSON.parse(localStorage.getItem('guestCart') || '[]');

    const existingItem = cart.find((item: any) => item.giftId === giftId);

    if (existingItem) {
      existingItem.quantity += 1;
    } else {
      cart.push({
        giftId,
        quantity: 1
      });
    }

    localStorage.setItem('guestCart', JSON.stringify(cart));
    console.log('Added to guest cart', cart);

  }





